import numpy as np

def concat_heads(heads):
    return np.concatenate(heads, axis=-1)

def run_practice():
    h1 = np.array([[1.0]])
    h2 = np.array([[2.0]])
    merged = concat_heads([h1, h2])
    assert np.allclose(merged, np.array([[1.0, 2.0]]))
    print('[PASS] Concatenation assertions passed.')

if __name__ == '__main__':
    run_practice()
